    // ===== Tsumo conditions =====

    String calcKoTsumoCondition(int p) {
        // p is ko (non-dealer)
        // For each tsumo threshold, check if p qualifies
        // p gains: 2 * ko_payment + 1 * oya_payment + kyoutaku*1000 - honba*100*3
        // Others: oya loses oya_payment, each of 2 ko loses ko_payment
        // Plus honba: each player pays +100*honba extra

        int minKo = -1, minOya = -1;
        for (int[] tv : KO_TSUMO) {
            int ko = tv[0] + honba * 100;
            int oya = tv[1] + honba * 100;
            int pGain = 2 * ko + oya + kyoutaku * 1000;
            // Build transfers
            int[][] transfers = buildKoTsumoTransfers(p, ko, oya);
            if (qualifiesAfterTransfer(p, -1, transfers)) {
                // adjust for kyoutaku already included in gain
                // Actually let's just check via scores
                int[] sc = Arrays.copyOf(scores, N);
                for (int i = 0; i < N; i++) {
                    if (i == p) continue;
                    int pay;
                    if (i == dealerIdx) pay = oya;
                    else pay = ko;
                    sc[i] -= pay;
                    sc[p] += pay;
                }
                sc[p] += kyoutaku * 1000;
                if (qualifiesWithScores(sc, p)) {
                    minKo = tv[0]; // original (before honba)
                    minOya = tv[1];
                    break;
                }
            }
        }

        // Re-compute properly
        minKo = -1; minOya = -1;
        for (int[] tv : KO_TSUMO) {
            int ko = tv[0] + honba * 100;
            int oya = tv[1] + honba * 100;
            int[] sc = applyKoTsumo(p, ko, oya);
            if (qualifiesWithScores(sc, p)) {
                minKo = tv[0];
                minOya = tv[1];
                break;
            }
        }

        if (minKo < 0) {
            // Even yakuman not enough
            return "不可能晋级";
        }

        // Always achievable with any tsumo?
        int[] scMin = applyKoTsumo(p, 300 + honba * 100, 500 + honba * 100);
        if (qualifiesWithScores(scMin, p)) {
            return "300・500以上";
        }

        return minKo + "・" + minOya + "以上";
    }

    int[] applyKoTsumo(int p, int ko, int oya) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            int pay = (i == dealerIdx) ? oya : ko;
            sc[i] -= pay;
            sc[p] += pay;
        }
        sc[p] += kyoutaku * 1000;
        return sc;
    }

    int[][] buildKoTsumoTransfers(int p, int ko, int oya) {
        List<int[]> t = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            int pay = (i == dealerIdx) ? oya : ko;
            t.add(new int[]{i, p, pay});
        }
        return t.toArray(new int[0][]);
    }

    String calcOyaTsumoCondition(int p) {
        // p is oya (dealer)
        // All 3 others pay oya_all
        for (int all : OYA_TSUMO) {
            int allH = all + honba * 100;
            int[] sc = applyOyaTsumo(p, allH);
            if (qualifiesWithScores(sc, p)) {
                if (all == OYA_TSUMO[0]) {
                    return oyaTsumoLabel(OYA_TSUMO[0]) + "以上";
                }
                return oyaTsumoLabel(all) + "以上";
            }
        }
        return "不可能晋级";
    }

    int[] applyOyaTsumo(int p, int allPayment) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            sc[i] -= allPayment;
            sc[p] += allPayment;
        }
        sc[p] += kyoutaku * 1000;
        return sc;
    }

    // ===== Ron conditions (p wins) =====

    String calcRonCondition(int p, int loser) {
        // p wins by ron from loser
        // p is dealer or not?
        boolean pIsOya = (p == dealerIdx);
        int[] thresholds = pIsOya ? OYA_RON : KO_RON;

        for (int v : thresholds) {
            int vH = v + honba * 300;
            int[] sc = applyRon(p, loser, vH);
            if (qualifiesWithScores(sc, p)) {
                // check if minimum also works
                if (v == thresholds[0]) {
                    return thresholds[0] + "以上";
                }
                return v + "以上";
            }
        }
        return "不可能晋级";
    }

    int[] applyRon(int winner, int loser, int amount) {
        int[] sc = Arrays.copyOf(scores, N);
        sc[loser] -= amount;
        sc[winner] += amount;
        sc[winner] += kyoutaku * 1000;
        return sc;
    }

    // ===== Dealin conditions (p deals into other) =====

    List<String> calcDealinCondition(int p, int winner) {
        // p pays ron to winner
        // We want conditions where p still qualifies
        // Find max payment that p can afford and still qualify
        boolean winnerIsOya = (winner == dealerIdx);
        int[] thresholds = winnerIsOya ? OYA_RON : KO_RON;

        List<String> results = new ArrayList<>();

        // Find the maximum threshold where p still qualifies
        int maxOk = -1;
        boolean qualifiesMin = false;

        // Check from min to max
        boolean prevQualifies = false;
        int firstFail = -1;
        int lastOk = -1;

        for (int v : thresholds) {
            int vH = v + honba * 300;
            int[] sc = applyRon(winner, p, vH);
            boolean q = qualifiesWithScores(sc, p);
            if (q) {
                lastOk = v;
            }
        }

        // Check if p qualifies even with max payment (yakuman)
        int maxV = thresholds[thresholds.length - 1];
        int[] scMax = applyRon(winner, p, maxV + honba * 300);
        if (qualifiesWithScores(scMax, p)) {
            // Always qualifies regardless of payment
            results.add("3倍役满以下");
            return results;
        }

        if (lastOk < 0) {
            // p cannot qualify even with 1000 ron
            return results; // empty = cannot qualify (already can't)
        }

        // Find range: [minFail, ...] causes p to lose qualification
        // There might be a gap (qualifies at high values again due to rank shifts)
        // Build complete picture
        List<int[]> okRanges = new ArrayList<>();
        boolean inOk = false;
        int rangeStart = -1;
        for (int v : thresholds) {
            int vH = v + honba * 300;
            int[] sc = applyRon(winner, p, vH);
            boolean q = qualifiesWithScores(sc, p);
            if (q && !inOk) {
                inOk = true;
                rangeStart = v;
            } else if (!q && inOk) {
                inOk = false;
                okRanges.add(new int[]{rangeStart, thresholds[indexOf(thresholds, v) - 1]});
            }
        }
        if (inOk) {
            okRanges.add(new int[]{rangeStart, thresholds[thresholds.length - 1]});
        }

        // Typically there's one continuous range from small to some max
        // Display as "X以下" meaning p can afford up to X
        if (okRanges.isEmpty()) {
            return results;
        }

        // Check if qualifies with no payment (current state)
        // If p qualifies currently (0 payment), and there's a threshold above which they don't:
        // Check current state
        int[] scCur = Arrays.copyOf(scores, N);
        // With 0 payment (just kyoutaku to winner if they win = no, this is for a potential dealin)
        // Current state without dealin: player p qualifies or not
        // But dealin context: if p deals into winner at amount=0 that's impossible
        // We use threshold[0] as minimum possible payment

        // Simple output: if p can still qualify paying up to lastOk, show "lastOk以下"
        // For each contiguous ok range
        if (okRanges.size() == 1) {
            int hi = okRanges.get(0)[1];
            int lo = okRanges.get(0)[0];
            if (lo == thresholds[0]) {
                // ok from minimum up to hi
                if (hi == thresholds[thresholds.length - 1]) {
                    results.add("3倍役满以下");
                } else {
                    results.add(labelRon(hi, winnerIsOya) + "以下");
                }
            } else {
                // only ok from lo onwards (unusual - means small payments hurt p?)
                results.add(labelRon(lo, winnerIsOya) + "以上" + labelRon(hi, winnerIsOya) + "以下");
            }
        } else {
            // Multiple ranges - output each
            for (int[] r : okRanges) {
                int lo = r[0], hi = r[1];
                if (lo == thresholds[0]) {
                    results.add(labelRon(hi, winnerIsOya) + "以下");
                } else if (hi == thresholds[thresholds.length - 1]) {
                    results.add(labelRon(lo, winnerIsOya) + "以上");
                } else {
                    results.add(labelRon(lo, winnerIsOya) + "以上" + labelRon(hi, winnerIsOya) + "以下");
                }
            }
        }

        return results;
    }

    String labelRon(int v, boolean isOya) {
        return isOya ? oyaRonLabel(v) : koRonLabel(v);
    }

    int indexOf(int[] arr, int v) {
        for (int i = 0; i < arr.length; i++) if (arr[i] == v) return i;
        return -1;
    }

    // ===== Being tsumo'd conditions =====

    List<String> calcTsumoedCondition(int p, int tsumoer, boolean tsumoerIsOya) {
        // tsumoer wins by tsumo, p is one of the payers
        // p pays: if tsumoer is oya: oya_payment; if tsumoer is ko:
        //   if p is oya: oya_payment, else: ko_payment
        // Find conditions where p still qualifies

        List<String> results = new ArrayList<>();

        if (tsumoerIsOya) {
            // Oya tsumo: all pay oyaTsumo amount
            // Check all thresholds
            boolean prevQ = false;
            int lastOk = -1;
            for (int all : OYA_TSUMO) {
                int allH = all + honba * 100;
                int[] sc = applyOyaTsumo(tsumoer, allH);
                boolean q = qualifiesWithScores(sc, p);
                if (q) lastOk = all;
            }

            int[] scMax = applyOyaTsumo(tsumoer, OYA_TSUMO[OYA_TSUMO.length - 1] + honba * 100);
            if (qualifiesWithScores(scMax, p)) {
                results.add("3倍役满以下");
                return results;
            }

            if (lastOk < 0) return results;

            // Find ranges
            List<int[]> okRanges = new ArrayList<>();
            boolean inOk = false; int rangeStart = -1;
            for (int all : OYA_TSUMO) {
                int allH = all + honba * 100;
                int[] sc = applyOyaTsumo(tsumoer, allH);
                boolean q = qualifiesWithScores(sc, p);
                if (q && !inOk) { inOk = true; rangeStart = all; }
                else if (!q && inOk) {
                    inOk = false;
                    okRanges.add(new int[]{rangeStart, prevOyaTsumo(all)});
                }
                prevQ = q;
            }
            if (inOk) okRanges.add(new int[]{rangeStart, OYA_TSUMO[OYA_TSUMO.length - 1]});

            for (int[] r : okRanges) {
                int lo = r[0], hi = r[1];
                if (lo == OYA_TSUMO[0]) {
                    results.add(oyaTsumoLabel(hi) + "以下");
                } else if (hi == OYA_TSUMO[OYA_TSUMO.length - 1]) {
                    results.add(oyaTsumoLabel(lo) + "以上");
                } else {
                    results.add(oyaTsumoLabel(lo) + "以上" + oyaTsumoLabel(hi) + "以下");
                }
            }
        } else {
            // Ko tsumo: p pays based on whether p is oya or ko
            // Check all KO_TSUMO thresholds
            boolean pIsOyaHere = (p == dealerIdx);

            List<int[]> okRanges = new ArrayList<>();
            boolean inOk = false; int[] rangeStart = null;
            int prevKo = -1, prevOya2 = -1;
            for (int[] tv : KO_TSUMO) {
                int ko = tv[0] + honba * 100;
                int oya = tv[1] + honba * 100;
                int[] sc = applyKoTsumo(tsumoer, ko, oya);
                boolean q = qualifiesWithScores(sc, p);
                if (q && !inOk) { inOk = true; rangeStart = tv; }
                else if (!q && inOk) {
                    inOk = false;
                    okRanges.add(new int[]{rangeStart[0], rangeStart[1], prevKo, prevOya2});
                }
                prevKo = tv[0]; prevOya2 = tv[1];
            }
            if (inOk) okRanges.add(new int[]{rangeStart[0], rangeStart[1], KO_TSUMO[KO_TSUMO.length-1][0], KO_TSUMO[KO_TSUMO.length-1][1]});

            // Check if qualifies with max
            int[] scMax = applyKoTsumo(tsumoer, KO_TSUMO[KO_TSUMO.length-1][0] + honba * 100, KO_TSUMO[KO_TSUMO.length-1][1] + honba * 100);
            if (qualifiesWithScores(scMax, p)) {
                results.add("3倍役满以下");
                return results;
            }

            for (int[] r : okRanges) {
                int loKo = r[0], loOya = r[1], hiKo = r[2], hiOya = r[3];
                if (loKo == KO_TSUMO[0][0] && loOya == KO_TSUMO[0][1]) {
                    results.add(koTsumoLabel(hiKo, hiOya) + "以下");
                } else if (hiKo == KO_TSUMO[KO_TSUMO.length-1][0] && hiOya == KO_TSUMO[KO_TSUMO.length-1][1]) {
                    results.add(koTsumoLabel(loKo, loOya) + "以上");
                } else {
                    results.add(koTsumoLabel(loKo, loOya) + "以上" + koTsumoLabel(hiKo, hiOya) + "以下");
                }
            }
        }

        return results;
    }

    int prevOyaTsumo(int v) {
        int prev = -1;
        for (int x : OYA_TSUMO) {
            if (x == v) return prev;
            prev = x;
        }
        return v;
    }

    // ===== Danger zones =====

    void calculateDangerZones(int p) {
        // For each pair (a, b) where a != p and b != p and a != b:
        // If a pays b (ron), does that cause p to lose qualification?
        // Find the range of payments where p loses

        boolean hasAny = false;

        for (int a = 0; a < N; a++) {
            if (a == p) continue;
            for (int b = 0; b < N; b++) {
                if (b == p || b == a) continue;
                // a deals into b (a pays b by ron)
                boolean bIsOya = (b == dealerIdx);
                int[] thresholds = bIsOya ? OYA_RON : KO_RON;

                // Check if p loses qualification for any payment in range
                int firstDanger = -1, lastDanger = -1;
                // We want: range where p does NOT qualify
                for (int v : thresholds) {
                    int vH = v + honba * 300;
                    int[] sc = Arrays.copyOf(scores, N);
                    sc[a] -= vH;
                    sc[b] += vH;
                    sc[b] += kyoutaku * 1000; // kyoutaku goes to winner
                    boolean q = qualifiesWithScores(sc, p);
                    if (!q) {
                        if (firstDanger < 0) firstDanger = v;
                        lastDanger = v;
                    }
                }

                if (firstDanger < 0) continue; // never loses qualification

                // Build danger range string
                String lo, hi;
                if (firstDanger == thresholds[0]) {
                    // Loses from minimum
                    if (lastDanger == thresholds[thresholds.length - 1]) {
                        // Always loses regardless
                        println(names[a] + "点" + names[b] + "\t任何点数都会丢晋级资格");
                    } else {
                        hi = labelRon(lastDanger, bIsOya);
                        println(names[a] + "点" + names[b] + "\t" + hi + "以下会丢晋级资格");
                    }
                } else {
                    lo = labelRon(firstDanger, bIsOya);
                    if (lastDanger == thresholds[thresholds.length - 1]) {
                        hi = "3倍役满";
                        if (firstDanger == thresholds[thresholds.length - 1]) {
                            println(names[a] + "点" + names[b] + "\t" + lo + "以上3倍役满以下会丢晋级资格");
                        } else {
                            println(names[a] + "点" + names[b] + "\t" + lo + "以上3倍役满以下会丢晋级资格");
                        }
                    } else {
                        hi = labelRon(lastDanger, bIsOya);
                        println(names[a] + "点" + names[b] + "\t" + lo + "以上" + hi + "以下会丢晋级资格");
                    }
                }
                hasAny = true;
            }
        }
        // If no danger zones, print nothing (blank line already added in caller)
    }

    // ===== Ryuukyoku (exhaustive draw) section =====

    void calculateRyuukyoku() {
        println("【听牌分支一览】");

        // M-League: tenpai-noten rule
        // Tenpai players gain, noten players lose
        // 3000 pts to field shared by tenpai players
        // Tenpai: 0 players -> no transfer
        // 1 tenpai: +3000
        // 2 tenpai: +1500 each, noten -1500 each
        // 3 tenpai: +1000 each, noten -3000
        // 4 tenpai: no transfer

        // 16 combinations: each player can be tenpai (T) or noten (N)
        // Display: name the combination, then list who advances
        // If dealer is tenpai: game continues (dealer repeats)

        // Enumerate all 16 combinations
        for (int mask = 0; mask < 16; mask++) {
            calculateRyuukyokuCase(mask);
        }
    }

    void calculateRyuukyokuCase(int mask) {
        // mask bit i: 1 = player i is tenpai, 0 = noten
        // Calculate point transfer
        int tenpaiCount = Integer.bitCount(mask);

        int[] sc = Arrays.copyOf(scores, N);

        // Tenpai-noten transfer
        if (tenpaiCount > 0 && tenpaiCount < 4) {
            int tenpaiGain = 3000 / tenpaiCount; // each tenpai player gains
            int notenLoss = 3000 / (4 - tenpaiCount); // each noten player loses
            for (int i = 0; i < N; i++) {
                if ((mask >> i & 1) == 1) {
                    sc[i] += tenpaiGain;
                } else {
                    sc[i] -= notenLoss;
                }
            }
        }

        // Kyoutaku stays on table (not distributed in ryuukyoku)
        // But in M-League: if this is the last hand (South-4) and it ends in ryuukyoku,
        // kyoutaku goes to top player
        // Find top player
        int[] topSc = Arrays.copyOf(sc, N);
        // Add kyoutaku to top player
        int topIdx = 0;
        for (int i = 1; i < N; i++) {
            if (sc[i] > sc[topIdx] || (sc[i] == sc[topIdx] && seats[i] < seats[topIdx])) {
                topIdx = i;
            }
        }
        topSc[topIdx] += kyoutaku * 1000;

        // If dealer is tenpai: game continues (not final)
        boolean dealerTenpai = (mask >> dealerIdx & 1) == 1;

        // Determine qualifiers
        List<String> qualifiers = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            if (qualifiesWithScores(topSc, i)) {
                qualifiers.add(names[i]);
            }
        }

        // Case name
        String caseName = getRyuukyokuCaseName(mask);

        String qualStr = "[" + String.join(", ", qualifiers) + "]晋级";
        String note = "";
        if (dealerTenpai) {
            note = "，但" + names[dealerIdx] + "听牌而继续";
        }

        println(caseName + "：" + qualStr + note);
    }

    String getRyuukyokuCaseName(int mask) {
        int count = Integer.bitCount(mask);
        if (count == 0) return "全员未听牌";
        if (count == 4) return "全员听牌";
        if (count == 1) {
            for (int i = 0; i < N; i++) {
                if ((mask >> i & 1) == 1) return names[i] + "一人听牌";
            }
        }
        if (count == 3) {
            // One person not tenpai
            for (int i = 0; i < N; i++) {
                if ((mask >> i & 1) == 0) return names[i] + "一人未听牌";
            }
        }
        // count == 2: two tenpai
        List<String> tenpaiNames = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            if ((mask >> i & 1) == 1) tenpaiNames.add(names[i]);
        }
        return tenpaiNames.get(0) + "、" + tenpaiNames.get(1) + "听牌";
    }

    // Override applyOyaTsumo to work for the tsumoer directly
    int[] applyOyaTsumo(int tsumoer, int allPayment) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == tsumoer) continue;
            sc[i] -= allPayment;
            sc[tsumoer] += allPayment;
        }
        sc[tsumoer] += kyoutaku * 1000;
        return sc;
    }
}
