{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * Riichi Mahjong Promotion Condition Calculator
 *
 * Supports: M-League, A-Rule (JPML), WRC, Saikouisen rules
 *
 * Usage: java MahjongPromotionCalculator < input.txt
 */
public class MahjongPromotionCalculator {

    // ===== Rule sets =====
    enum RuleSet {
        M_LEAGUE("M-league"), A_RULE("A规"), WRC("WRC"), SAIKOUISEN("最高位");
        final String displayName;
        RuleSet(String name) { this.displayName = name; }
    }

    // Uma tables: index 0=1st, 1=2nd, 2=3rd, 3=4th
    // Values are in units of 0.1pt (multiply by 0.1 to get actual pt)
    static int[] getUma(RuleSet rule) {
        switch (rule) {
            case M_LEAGUE:   return new int[]{500, 100, -100, -300};
            case A_RULE:     return new int[]{200, 100, -100, -200};
            case WRC:        return new int[]{150,  50,  -50, -150};
            case SAIKOUISEN: return new int[]{300, 100, -100, -300};
            default:         return new int[]{500, 100, -100, -300};
        }
    }

    static int getReturnScore(RuleSet rule) {
        // M-League: 30000; others: 30000
        return 30000;
    }

    // ===== Payment threshold tables =====
    // Ko (non-dealer) ron payments
    static final int[] KO_RON  = {1000, 2000, 3900, 5200, 5800, 7700, 8000, 12000, 16000, 24000, 32000, 64000, 96000};
    // Oya (dealer) ron payments
    static final int[] OYA_RON = {1500, 2900, 3900, 5800, 7700, 8700, 11600, 12000, 18000, 24000, 36000, 48000, 96000, 144000};
    // Ko tsumo: {ko_payment, oya_payment}
    static final int[][] KO_TSUMO = {
        {300,500},{500,1000},{700,1300},{1000,2000},{2000,4000},{3000,6000},{4000,8000},{6000,12000},{8000,16000},{16000,32000},{24000,48000}
    };
    // Oya tsumo: each non-dealer pays this amount
    static final int[] OYA_TSUMO = {500,1000,2000,4000,8000,12000,16000,24000,32000,48000,96000,144000};

    // ===== Label helpers =====
    static String labelKoRon(int v) {
        if (v >= 96000) return "3倍役满";
        if (v >= 64000) return "2倍役满";
        if (v >= 32000) return "役满";
        return String.valueOf(v);
    }
    static String labelOyaRon(int v) {
        if (v >= 144000) return "3倍役满";
        if (v >= 96000)  return "2倍役满";
        if (v >= 48000)  return "亲役满";
        return String.valueOf(v);
    }
    static String labelRon(int v, boolean isWinnerOya) {
        return isWinnerOya ? labelOyaRon(v) : labelKoRon(v);
    }
    static String labelKoTsumo(int ko, int oya) {
        return ko + "・" + oya;
    }
    static String labelOyaTsumoAll(int all) {
        if (all >= 144000) return "3倍役满all";
        if (all >= 96000)  return "2倍役满all";
        if (all >= 48000)  return "役满all";
        return all + "all";
    }

    // ===== Game state =====
    int N = 4;
    String[] names;
    int[] seatOf;  // seatOf[i] = seat index of player i (0=East,1=South,2=West,3=North)
    double[] priorPt;
    int[] scores;
    int promotionTop;
    RuleSet rule;
    int kyoutaku;  // riichi sticks on table (each worth 1000 pts)
    int honba;     // honba counter
    int dealerIdx; // index (0-3) of current dealer

    // ===== PT calculation =====

    /**
     * Compute final pt for player i given their final score and rank (1-indexed).
     */
    double calcPt(int playerIdx, int finalScore, int rank) {
        int[] uma = getUma(rule);
        int ret = getReturnScore(rule);
        return priorPt[playerIdx] + (finalScore - ret) / 1000.0 + uma[rank - 1] / 10.0;
    }

    /**
     * Rank all players by score descending. Ties broken by seat order (lower seat index wins).
     * Returns rank array: ranks[i] = rank of player i (1=1st, ..., 4=4th).
     */
    int[] rankByScore(int[] sc) {
        Integer[] idx = {0, 1, 2, 3};
        Arrays.sort(idx, (a, b) -> {
            if (sc[b] != sc[a]) return sc[b] - sc[a];
            return seatOf[a] - seatOf[b]; // lower seat = East wins ties
        });
        int[] rank = new int[N];
        for (int i = 0; i < N; i++) rank[idx[i]] = i + 1;
        return rank;
    }

    /**
     * Check if player p qualifies (is in top-promotionTop by pt) given final scores.
     * kyoutakuWinner: if >= 0, that player gets all kyoutaku sticks.
     */
    boolean qualifiesWithScores(int[] sc, int p, int kyoutakuWinner) {
        int[] sc2 = Arrays.copyOf(sc, N);
        if (kyoutakuWinner >= 0) {
            sc2[kyoutakuWinner] += kyoutaku * 1000;
        }
        int[] ranks = rankByScore(sc2);
        double myPt = calcPt(p, sc2[p], ranks[p]);
        int worse = 0;
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            double theirPt = calcPt(i, sc2[i], ranks[i]);
            if (theirPt < myPt) worse++;
            // tie: if same pt, seat order determines rank (already handled in pt calculation
            // via score ranking → same rank would require same score + same uma which is impossible)
        }
        // qualifies if there are fewer than promotionTop players ahead of p
        // i.e., at most (promotionTop - 1) players have higher pt than p
        int ahead = N - 1 - worse; // players with >= myPt excluding p... let me redo
        int strictlyAhead = 0;
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            double theirPt = calcPt(i, sc2[i], ranks[i]);
            if (theirPt > myPt) strictlyAhead++;
            // Equal pt: resolve by seat order (same as score ranking - already factored in uma)
            // In practice, equal final pt is very rare but possible
        }
        return strictlyAhead < promotionTop;
    }

    // Convenience: kyoutaku goes to winner of this hand
    boolean qualifiesAfterWin(int[] sc, int p, int winner) {
        return qualifiesWithScores(sc, p, winner);
    }

    // For ryuukyoku: kyoutaku stays (goes to top score player at game end)
    boolean qualifiesRyuukyoku(int[] sc, int p) {
        // kyoutaku goes to top score player
        int topPlayer = 0;
        for (int i = 1; i < N; i++) {
            if (sc[i] > sc[topPlayer] || (sc[i] == sc[topPlayer] && seatOf[i] < seatOf[topPlayer])) {
                topPlayer = i;
            }
        }
        return qualifiesWithScores(sc, p, topPlayer);
    }

    // ===== Score manipulation helpers =====

    int[] applyKoTsumo(int tsumoer, int ko, int oya) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == tsumoer) continue;
            int pay = (i == dealerIdx) ? oya : ko;
            sc[i] -= pay;
            sc[tsumoer] += pay;
        }
        return sc;
    }

    int[] applyOyaTsumo(int tsumoer, int allPay) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == tsumoer) continue;
            sc[i] -= allPay;
            sc[tsumoer] += allPay;
        }
        return sc;
    }

    int[] applyRon(int winner, int loser, int amount) {
        int[] sc = Arrays.copyOf(scores, N);
        sc[loser] -= amount;
        sc[winner] += amount;
        return sc;
    }

    // ===== Main =====

    public static void main(String[] args) throws Exception {
        MahjongPromotionCalculator calc = new MahjongPromotionCalculator();
        calc.readInput(new BufferedReader(new InputStreamReader(System.in)));
        calc.calculate();
    }

    void readInput(BufferedReader br) throws Exception {
        names = new String[4];
        seatOf = new int[4];
        priorPt = new double[4];
        scores = new int[4];
        rule = RuleSet.M_LEAGUE;
        kyoutaku = 0;
        honba = 0;
        dealerIdx = 3;

        String dealerSeatStr = "北";
        String[] seatOrder = {"东", "南", "西", "北"};

        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (line.isEmpty()) continue;

            if (line.startsWith("当前亲家") || line.startsWith("当前親家")) {
                dealerSeatStr = after(line).trim();
            } else if (line.startsWith("座次")) {
                seatOrder = after(line).trim().split("\\s+");
            } else if (line.startsWith("名字")) {
                String[] ns = after(line).trim().split("\\s+");
                for (int i = 0; i < 4; i++) names[i] = ns[i];
            } else if (line.startsWith("开始前总分") || line.startsWith("開始前總分")) {
                String rest = line.replaceFirst("^开始前总分|^開始前總分", "").trim();
                String[] ps = rest.split("\\s+");
                for (int i = 0; i < 4; i++) priorPt[i] = Double.parseDouble(ps[i]);
            } else if (line.startsWith("当前分数") || line.startsWith("當前分數")) {
                String rest = line.replaceFirst("^当前分数|^當前分數", "").trim();
                String[] ss = rest.split("\\s+");
                for (int i = 0; i < 4; i++) scores[i] = Integer.parseInt(ss[i]);
            } else if (line.startsWith("晋级条件") || line.startsWith("晉級條件")) {
                String rest = after(line).trim();
                promotionTop = Integer.parseInt(rest.replaceAll("[^0-9]", "").substring(0, 1));
            } else if (line.startsWith("规则") || line.startsWith("規則")) {
                String rest = after(line).trim().toLowerCase();
                if (rest.contains("m") && rest.contains("league")) rule = RuleSet.M_LEAGUE;
                else if (rest.contains("wrc")) rule = RuleSet.WRC;
                else if (rest.contains("a") && (rest.contains("规") || rest.contains("rule"))) rule = RuleSet.A_RULE;
                else if (rest.contains("最高") || rest.contains("saikouisen")) rule = RuleSet.SAIKOUISEN;
                else rule = RuleSet.M_LEAGUE;
            } else if (line.startsWith("供托") || line.startsWith("供託")) {
                String rest = after(line).trim();
                kyoutaku = Integer.parseInt(rest.replaceAll("[^0-9]", ""));
            } else if (line.startsWith("本场") || line.startsWith("本場")) {
                String rest = after(line).trim();
                honba = Integer.parseInt(rest.replaceAll("[^0-9]", ""));
            }
        }

        // Build seat mapping
        for (int i = 0; i < 4; i++) {
            seatOf[i] = parseSeat(seatOrder[i]);
        }

        // Find dealer index
        int dealerSeatIdx = parseSeat(dealerSeatStr);
        dealerIdx = -1;
        for (int i = 0; i < 4; i++) {
            if (seatOf[i] == dealerSeatIdx) { dealerIdx = i; break; }
        }
        if (dealerIdx < 0) dealerIdx = 3;
    }

    String after(String line) {
        int c = line.indexOf('：');
        if (c < 0) c = line.indexOf(':');
        if (c >= 0) return line.substring(c + 1);
        // Try splitting after Chinese characters
        return line.replaceFirst("^[\\u4e00-\\u9fff]+", "");
    }

    int parseSeat(String s) {
        s = s.trim();
        switch (s) {
            case "东": case "東": return 0;
            case "南": return 1;
            case "西": return 2;
            case "北": return 3;
            default: return 0;
        }
    }

    // ===== Output =====

    StringBuilder out = new StringBuilder();
    void println(String s) { out.append(s).append("\n"); }

    void calculate() {
        for (int p = 0; p < N; p++) {
            printPlayerConditions(p);
        }
        printRyuukyoku();
        System.out.print(out.toString());
    }

    // ===== Per-player conditions =====

    void printPlayerConditions(int p) {
        println(names[p] + "晋级条件");

        // --- Tsumo ---
        boolean pIsOya = (p == dealerIdx);
        if (pIsOya) {
            String cond = calcOyaTsumoWin(p);
            println("自摸\t" + cond);
        } else {
            String cond = calcKoTsumoWin(p);
            println("自摸\t" + cond);
        }

        println("=============================");

        // --- Ron wins (p wins from others) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            String cond = calcRonWin(p, other);
            if (!cond.isEmpty()) {
                println(names[other] + "荣和\t" + cond);
            }
        }

        println("=============================");

        // --- Dealin (p deals into others) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            List<String> conds = calcDealin(p, other);
            for (String c : conds) {
                println("对" + names[other] + "放铳\t" + c);
            }
        }

        println("=============================");

        // --- Being tsumo'd (others tsumo, p pays) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            boolean otherIsOya = (other == dealerIdx);
            List<String> conds = calcBeingTsumod(p, other, otherIsOya);
            for (String c : conds) {
                if (otherIsOya) {
                    println("被" + names[other] + "亲家自摸\t" + c);
                } else {
                    println("被" + names[other] + "自摸\t" + c);
                }
            }
        }

        println("");
        println(names[p] + "危险区间:");
        printDangerZones(p);
        println("");
    }

    // ===== Tsumo win conditions =====

    String calcKoTsumoWin(int p) {
        // p is ko (non-dealer), wins by tsumo
        // oya pays oya_payment, 2 other ko each pay ko_payment
        // Plus honba: each player pays +100 extra per honba
        // Plus kyoutaku to p
        String firstQualLabel = null;
        for (int[] tv : KO_TSUMO) {
            int ko  = tv[0] + honba * 100;
            int oya = tv[1] + honba * 100;
            int[] sc = applyKoTsumo(p, ko, oya);
            if (qualifiesAfterWin(sc, p, p)) {
                if (firstQualLabel == null) {
                    firstQualLabel = labelKoTsumo(tv[0], tv[1]);
                    // Check if even minimum (first threshold) qualifies
                    if (tv[0] == KO_TSUMO[0][0]) {
                        return labelKoTsumo(KO_TSUMO[0][0], KO_TSUMO[0][1]) + "以上";
                    }
                    return firstQualLabel + "以上";
                }
            }
        }
        if (firstQualLabel != null) return firstQualLabel + "以上";
        return "不可能晋级";
    }

    String calcOyaTsumoWin(int p) {
        // p is oya (dealer), all 3 others pay allPayment
        for (int all : OYA_TSUMO) {
            int allH = all + honba * 100;
            int[] sc = applyOyaTsumo(p, allH);
            if (qualifiesAfterWin(sc, p, p)) {
                return labelOyaTsumoAll(all) + "以上";
            }
        }
        return "不可能晋级";
    }

    // ===== Ron win condition (p wins from 'from') =====

    String calcRonWin(int p, int from) {
        // p wins by ron from 'from'
        // Payment: if p is oya → oya_ron; if p is ko → ko_ron
        boolean pIsOya = (p == dealerIdx);
        int[] thresholds = pIsOya ? OYA_RON : KO_RON;

        for (int v : thresholds) {
            int vH = v + honba * 300;
            int[] sc = applyRon(p, from, vH);
            if (qualifiesAfterWin(sc, p, p)) {
                return labelRon(v, pIsOya) + "以上";
            }
        }
        return "不可能晋级";
    }

    // ===== Dealin condition (p pays to winner) =====

    List<String> calcDealin(int p, int winner) {
        // p deals into winner (p pays ron to winner)
        // Payment: if winner is oya → oya_ron; if winner is ko → ko_ron
        boolean winnerIsOya = (winner == dealerIdx);
        int[] thresholds = winnerIsOya ? OYA_RON : KO_RON;

        // For each threshold, check if p qualifies
        boolean[] qual = new boolean[thresholds.length];
        for (int i = 0; i < thresholds.length; i++) {
            int vH = thresholds[i] + honba * 300;
            int[] sc = applyRon(winner, p, vH);
            qual[i] = qualifiesAfterWin(sc, p, winner);
        }

        // Build contiguous OK ranges
        return buildRangeLabels(qual, thresholds, winnerIsOya, false);
    }

    /**
     * Build condition labels from a boolean array of qualifying states.
     * Each entry corresponds to a threshold value.
     * isOya: true if the relevant player is dealer (affects labels).
     * isOyaTsumo: use oyaTsumo labels (for tsumo conditions from others).
     */
    List<String> buildRangeLabels(boolean[] qual, int[] thresholds, boolean isOya, boolean isAbove) {
        List<String> results = new ArrayList<>();
        int n = thresholds.length;

        // Find contiguous ranges where qual[i] = true
        int i = 0;
        while (i < n) {
            if (qual[i]) {
                int start = i;
                while (i < n && qual[i]) i++;
                int end = i - 1;
                // Range is [start, end]
                String lo = labelRon(thresholds[start], isOya);
                String hi = labelRon(thresholds[end], isOya);

                if (start == 0 && end == n - 1) {
                    // Always qualifies
                    results.add("3倍役满以下");
                } else if (start == 0) {
                    results.add(hi + "以下");
                } else if (end == n - 1) {
                    results.add(lo + "以上");
                } else {
                    results.add(lo + (isAbove ? "以上" : "") + hi + "以下");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    // ===== Being tsumo'd conditions =====

    List<String> calcBeingTsumod(int p, int tsumoer, boolean tsumoerIsOya) {
        List<String> results = new ArrayList<>();

        if (tsumoerIsOya) {
            // Oya tsumo: all pay allPayment
            boolean[] qual = new boolean[OYA_TSUMO.length];
            for (int i = 0; i < OYA_TSUMO.length; i++) {
                int allH = OYA_TSUMO[i] + honba * 100;
                int[] sc = applyOyaTsumo(tsumoer, allH);
                qual[i] = qualifiesAfterWin(sc, p, tsumoer);
            }
            return buildTsumoRangeLabels(qual, OYA_TSUMO, true);
        } else {
            // Ko tsumo: p pays ko or oya payment depending on p's seat
            boolean[] qual = new boolean[KO_TSUMO.length];
            for (int i = 0; i < KO_TSUMO.length; i++) {
                int ko  = KO_TSUMO[i][0] + honba * 100;
                int oya = KO_TSUMO[i][1] + honba * 100;
                int[] sc = applyKoTsumo(tsumoer, ko, oya);
                qual[i] = qualifiesAfterWin(sc, p, tsumoer);
            }
            return buildKoTsumoRangeLabels(qual);
        }
    }

    List<String> buildTsumoRangeLabels(boolean[] qual, int[] thresholds, boolean isOyaTsumo) {
        List<String> results = new ArrayList<>();
        int n = thresholds.length;

        int i = 0;
        while (i < n) {
            if (qual[i]) {
                int start = i;
                while (i < n && qual[i]) i++;
                int end = i - 1;

                String lo = isOyaTsumo ? labelOyaTsumoAll(thresholds[start]) : labelKoTsumo(KO_TSUMO[start][0], KO_TSUMO[start][1]);
                String hi = isOyaTsumo ? labelOyaTsumoAll(thresholds[end])   : labelKoTsumo(KO_TSUMO[end][0], KO_TSUMO[end][1]);

                if (start == 0 && end == n - 1) {
                    results.add("3倍役满以下");
                } else if (start == 0) {
                    results.add(hi + "以下");
                } else if (end == n - 1) {
                    results.add(lo + "以上");
                } else {
                    results.add(lo + hi + "以下");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    List<String> buildKoTsumoRangeLabels(boolean[] qual) {
        List<String> results = new ArrayList<>();
        int n = KO_TSUMO.length;
        int i = 0;
        while (i < n) {
            if (qual[i]) {
                int start = i;
                while (i < n && qual[i]) i++;
                int end = i - 1;

                String lo = labelKoTsumo(KO_TSUMO[start][0], KO_TSUMO[start][1]);
                String hi = labelKoTsumo(KO_TSUMO[end][0], KO_TSUMO[end][1]);

                if (start == 0 && end == n - 1) {
                    results.add("3倍役满以下");
                } else if (start == 0) {
                    results.add(hi + "以下");
                } else if (end == n - 1) {
                    results.add(lo + "以上");
                } else {
                    // Multiple non-contiguous ranges within ko tsumo
                    results.add(lo + "以上" + hi + "以下");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    // ===== Danger zones =====

    void printDangerZones(int p) {
        // For each pair (a, b) both != p, a != b:
        // a pays b by ron → when does p lose qualification?
        boolean found = false;
        for (int a = 0; a < N; a++) {
            if (a == p) continue;
            for (int b = 0; b < N; b++) {
                if (b == p || b == a) continue;
                String dz = calcDangerZone(p, a, b);
                if (!dz.isEmpty()) {
                    println(names[a] + "点" + names[b] + "\t" + dz);
                    found = true;
                }
            }
        }
        // If no danger zones, just leave blank
    }

    String calcDangerZone(int p, int payer, int winner) {
        // payer pays winner. When does p NOT qualify?
        boolean winnerIsOya = (winner == dealerIdx);
        int[] thresholds = winnerIsOya ? OYA_RON : KO_RON;

        // For each threshold, check if p does NOT qualify
        boolean[] danger = new boolean[thresholds.length];
        for (int i = 0; i < thresholds.length; i++) {
            int vH = thresholds[i] + honba * 300;
            int[] sc = applyRon(winner, payer, vH);
            // kyoutaku goes to winner
            danger[i] = !qualifiesAfterWin(sc, p, winner);
        }

        // Build danger ranges
        List<String> dangerRanges = new ArrayList<>();
        int n = thresholds.length;
        int i = 0;
        while (i < n) {
            if (danger[i]) {
                int start = i;
                while (i < n && danger[i]) i++;
                int end = i - 1;
                String lo = labelRon(thresholds[start], winnerIsOya);
                String hi = labelRon(thresholds[end], winnerIsOya);
                if (start == 0 && end == n - 1) {
                    dangerRanges.add("任何点数都会丢晋级资格");
                } else if (start == 0) {
                    dangerRanges.add(hi + "以下会丢晋级资格");
                } else if (end == n - 1) {
                    dangerRanges.add(lo + "以上3倍役满以下会丢晋级资格");
                } else {
                    dangerRanges.add(lo + "以上" + hi + "以下会丢晋级资格");
                }
            } else {
                i++;
            }
        }

        return String.join("\n" + names[payer] + "点" + names[winner] + "\t", dangerRanges);
    }

    // ===== Ryuukyoku =====

    void printRyuukyoku() {
        println("【听牌分支一览】");

        // Enumerate all 16 tenpai/noten combinations
        // bit i: 1=player i is tenpai
        // Order: mask 0..15, but print in logical order
        // Actually print in the order shown in the sample:
        // 全不听 → 全听 → each 1-tenpai → each 1-noten → each 2-tenpai pair
        int[] order = {0, 15, 1, 2, 4, 8, 14, 13, 11, 7, 3, 5, 9, 6, 10, 12};
        for (int mask : order) {
            printRyuukyokuCase(mask);
        }
    }

    void printRyuukyokuCase(int mask) {
        int tenpaiCount = Integer.bitCount(mask);
        int[] sc = Arrays.copyOf(scores, N);

        // Tenpai-noten transfer (M-League style: 3000 total to field)
        if (tenpaiCount > 0 && tenpaiCount < 4) {
            // Calculate tenpai gain and noten loss per player
            // Total: 3000 = tenpaiCount * gain = (4-tenpaiCount) * loss
            // gain * tenpaiCount = 3000
            // Various distributions:
            // 1T3N: +3000 for T, -1000 each for N
            // 2T2N: +1500 each for T, -1500 each for N
            // 3T1N: +1000 each for T, -3000 for N
            int gain = 3000 / tenpaiCount;
            int loss = 3000 / (4 - tenpaiCount);
            for (int i = 0; i < N; i++) {
                if ((mask >> i & 1) == 1) {
                    sc[i] += gain;
                } else {
                    sc[i] -= loss;
                }
            }
        }

        // Kyoutaku goes to top score player at game end (ryuukyoku end)
        // Determine qualifiers
        List<String> qualifiers = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            if (qualifiesRyuukyoku(sc, i)) {
                qualifiers.add(names[i]);
            }
        }

        // Case name
        String caseName = ryuukyokuCaseName(mask);

        // If dealer is tenpai, note that game continues
        boolean dealerTenpai = (mask >> dealerIdx & 1) == 1;

        String qualStr = "[" + String.join(", ", qualifiers) + "]晋级";
        String note = dealerTenpai ? "，但" + names[dealerIdx] + "听牌而继续" : "";

        println(caseName + "：" + qualStr + note);
    }

    String ryuukyokuCaseName(int mask) {
        int count = Integer.bitCount(mask);
        if (count == 0) return "全员未听牌";
        if (count == 4) return "全员听牌";
        if (count == 1) {
            for (int i = 0; i < N; i++)
                if ((mask >> i & 1) == 1) return names[i] + "一人听牌";
        }
        if (count == 3) {
            for (int i = 0; i < N; i++)
                if ((mask >> i & 1) == 0) return names[i] + "一人未听牌";
        }
        // count == 2
        List<String> tenpaiNames = new ArrayList<>();
        for (int i = 0; i < N; i++)
            if ((mask >> i & 1) == 1) tenpaiNames.add(names[i]);
        return tenpaiNames.get(0) + "、" + tenpaiNames.get(1) + "听牌";
    }
