{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * Riichi Mahjong Promotion Condition Calculator
 *
 * Supports: M-League, A-Rule (JPML), WRC, Saikouisen rules
 *
 * Usage: java MahjongPromotionCalculator < input.txt
 */
public class MahjongPromotionCalculator {

    // ===== Rule sets =====
    enum RuleSet {
        M_LEAGUE, A_RULE, WRC, SAIKOUISEN;
    }

    // Uma tables: index 0=1st, 1=2nd, 2=3rd, 3=4th
    // Values in units of 0.1pt (multiply by 0.1 to get actual pt)
    static int[] getUma(RuleSet rule) {
        switch (rule) {
            case M_LEAGUE:   return new int[]{500, 100, -100, -300};
            case A_RULE:     return new int[]{200, 100, -100, -200};
            case WRC:        return new int[]{150,  50,  -50, -150};
            case SAIKOUISEN: return new int[]{300, 100, -100, -300};
            default:         return new int[]{500, 100, -100, -300};
        }
    }

    static int getReturnScore(RuleSet rule) {
        return 30000; // All major rulesets use 30000 return
    }

    // ===== Payment threshold tables =====
    // Standard ron and tsumo payment values from Japanese mahjong scoring tables

    // Ko (non-dealer) ron payments — all meaningful values from fu/han tables plus special
    static final int[] KO_RON = {
        1000, 1300, 1500, 1600, 2000, 2300, 2600, 2900, 3200, 3600, 3900,
        4500, 5200, 5800, 6400, 7100, 7700,
        8000,   // mangan
        12000,  // haneman
        16000,  // baiman
        24000,  // sanbaiman
        32000,  // yakuman
        64000,  // 2x yakuman
        96000   // 3x yakuman
    };

    // Oya (dealer) ron payments
    static final int[] OYA_RON = {
        1500, 2000, 2400, 2900, 3400, 3900, 4400, 4800, 5300, 5800, 6800, 7700,
        8700, 9600, 10600, 11600,
        12000,  // mangan
        18000,  // haneman
        24000,  // baiman
        36000,  // sanbaiman
        48000,  // yakuman
        96000,  // 2x yakuman
        144000  // 3x yakuman
    };

    // Ko tsumo: {ko_payment, oya_payment} per player
    static final int[][] KO_TSUMO = {
        {300, 500}, {500, 1000}, {700, 1300}, {800, 1600}, {1000, 2000},
        {1300, 2600}, {1500, 2900}, {1600, 3200}, {2000, 3900},
        {2000, 4000},  // mangan
        {3000, 6000},  // haneman
        {4000, 8000},  // baiman
        {6000, 12000}, // sanbaiman
        {8000, 16000}, // yakuman
        {16000, 32000},// 2x yakuman
        {24000, 48000} // 3x yakuman
    };

    // Oya tsumo: each ko pays this amount (all-pay)
    static final int[] OYA_TSUMO = {
        500, 1000, 1500, 2000, 2600, 3000, 3900,
        4000,   // mangan
        6000,   // haneman
        8000,   // baiman
        12000,  // sanbaiman
        16000,  // yakuman
        32000,  // 2x yakuman
        48000   // 3x yakuman
    };

    // ===== Label helpers =====
    static String labelKoRon(int v) {
        if (v >= 96000) return "3倍役满";
        if (v >= 64000) return "2倍役满";
        if (v >= 32000) return "役满";
        return String.valueOf(v);
    }
    static String labelOyaRon(int v) {
        if (v >= 144000) return "3倍役满";
        if (v >= 96000)  return "2倍役满";
        if (v >= 48000)  return "亲役满";
        return String.valueOf(v);
    }
    static String labelRon(int v, boolean isWinnerOya) {
        return isWinnerOya ? labelOyaRon(v) : labelKoRon(v);
    }
    static String labelKoTsumo(int ko, int oya) {
        return ko + "・" + oya;
    }
    static String labelOyaTsumoAll(int all) {
        if (all >= 48000) return "3倍役满all";
        if (all >= 32000) return "2倍役满all";
        if (all >= 16000) return "役满all";
        return all + "all";
    }

    // ===== Game state =====
    int N = 4;
    String[] names;
    int[] seatOf;      // seatOf[i] = seat index of player i (0=East,1=South,2=West,3=North)
    double[] priorPt;
    int[] scores;
    int promotionTop;
    RuleSet rule;
    int kyoutaku;      // riichi sticks on table (each = 1000 pts)
    int honba;         // honba counter (each = 300 pts to winner, 100 extra from each payer for tsumo)
    int dealerIdx;     // index (0-3) of current dealer (oya)

    // ===== PT calculation =====

    double calcPt(int playerIdx, int finalScore, int rank) {
        int[] uma = getUma(rule);
        int ret = getReturnScore(rule);
        return priorPt[playerIdx] + (finalScore - ret) / 1000.0 + uma[rank - 1] / 10.0;
    }

    /**
     * Rank all players by score descending.
     * Ties broken by seat order: lower seat index (East < South < West < North) wins.
     * Returns ranks[i] = rank of player i (1-indexed).
     */
    int[] rankByScore(int[] sc) {
        Integer[] idx = {0, 1, 2, 3};
        Arrays.sort(idx, (a, b) -> {
            if (sc[b] != sc[a]) return sc[b] - sc[a];
            return seatOf[a] - seatOf[b]; // lower seat = East wins ties
        });
        int[] rank = new int[N];
        for (int i = 0; i < N; i++) rank[idx[i]] = i + 1;
        return rank;
    }

    /**
     * Check if player p qualifies (top-promotionTop by pt) given final scores.
     * kyoutakuWinner: if >= 0, that player gets all kyoutaku sticks (1000 pts each).
     */
    boolean qualifiesWithScores(int[] sc, int p, int kyoutakuWinner) {
        int[] sc2 = Arrays.copyOf(sc, N);
        if (kyoutakuWinner >= 0) {
            sc2[kyoutakuWinner] += kyoutaku * 1000;
        }
        int[] ranks = rankByScore(sc2);
        double myPt = calcPt(p, sc2[p], ranks[p]);
        int strictlyAhead = 0;
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            double theirPt = calcPt(i, sc2[i], ranks[i]);
            if (theirPt > myPt) strictlyAhead++;
        }
        return strictlyAhead < promotionTop;
    }

    // For ryuukyoku: kyoutaku goes to top score player
    boolean qualifiesRyuukyoku(int[] sc, int p) {
        int topPlayer = 0;
        for (int i = 1; i < N; i++) {
            if (sc[i] > sc[topPlayer] || (sc[i] == sc[topPlayer] && seatOf[i] < seatOf[topPlayer])) {
                topPlayer = i;
            }
        }
        return qualifiesWithScores(sc, p, topPlayer);
    }

    // ===== Score manipulation helpers =====

    int[] applyKoTsumo(int tsumoer, int ko, int oya) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == tsumoer) continue;
            int pay = (i == dealerIdx) ? oya : ko;
            sc[i] -= pay;
            sc[tsumoer] += pay;
        }
        return sc;
    }

    int[] applyOyaTsumo(int tsumoer, int allPay) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int i = 0; i < N; i++) {
            if (i == tsumoer) continue;
            sc[i] -= allPay;
            sc[tsumoer] += allPay;
        }
        return sc;
    }

    int[] applyRon(int winner, int loser, int amount) {
        int[] sc = Arrays.copyOf(scores, N);
        sc[loser] -= amount;
        sc[winner] += amount;
        return sc;
    }

    // ===== Main =====

    public static void main(String[] args) throws Exception {
        MahjongPromotionCalculator calc = new MahjongPromotionCalculator();
        calc.readInput(new BufferedReader(new InputStreamReader(System.in)));
        calc.calculate();
    }

    void readInput(BufferedReader br) throws Exception {
        names    = new String[4];
        seatOf   = new int[4];
        priorPt  = new double[4];
        scores   = new int[4];
        rule     = RuleSet.M_LEAGUE;
        kyoutaku = 0;
        honba    = 0;
        dealerIdx = 3;

        String dealerSeatStr = "北";
        String[] seatOrder   = {"东", "南", "西", "北"};

        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (line.isEmpty()) continue;

            if (line.startsWith("当前亲家") || line.startsWith("当前親家")) {
                dealerSeatStr = after(line).trim();
            } else if (line.startsWith("座次")) {
                seatOrder = after(line).trim().split("\\s+");
            } else if (line.startsWith("名字")) {
                String[] ns = after(line).trim().split("\\s+");
                for (int i = 0; i < 4; i++) names[i] = ns[i];
            } else if (line.startsWith("开始前总分") || line.startsWith("開始前總分")) {
                String rest = line.replaceFirst("^开始前总分|^開始前總分", "").trim();
                String[] ps = rest.split("\\s+");
                for (int i = 0; i < 4; i++) priorPt[i] = Double.parseDouble(ps[i]);
            } else if (line.startsWith("当前分数") || line.startsWith("當前分數")) {
                String rest = line.replaceFirst("^当前分数|^當前分數", "").trim();
                String[] ss = rest.split("\\s+");
                for (int i = 0; i < 4; i++) scores[i] = Integer.parseInt(ss[i]);
            } else if (line.startsWith("晋级条件") || line.startsWith("晉級條件")) {
                String rest = after(line).trim().replaceAll("[^0-9]", "");
                if (!rest.isEmpty()) promotionTop = Integer.parseInt(rest.substring(0, 1));
            } else if (line.startsWith("规则") || line.startsWith("規則")) {
                String rest = after(line).trim().toLowerCase()
                    .replace("_", "").replace("-", "").replace(" ", "");
                if (rest.contains("mleague"))         rule = RuleSet.M_LEAGUE;
                else if (rest.contains("wrc"))        rule = RuleSet.WRC;
                else if (rest.startsWith("a") || rest.contains("a规") || rest.contains("arule"))
                                                      rule = RuleSet.A_RULE;
                else if (rest.contains("最高") || rest.contains("saikouisen"))
                                                      rule = RuleSet.SAIKOUISEN;
                else                                  rule = RuleSet.M_LEAGUE;
            } else if (line.startsWith("供托") || line.startsWith("供託")) {
                String rest = after(line).trim().replaceAll("[^0-9]", "");
                if (!rest.isEmpty()) kyoutaku = Integer.parseInt(rest);
            } else if (line.startsWith("本场") || line.startsWith("本場")) {
                String rest = after(line).trim().replaceAll("[^0-9]", "");
                if (!rest.isEmpty()) honba = Integer.parseInt(rest);
            }
        }

        // Build seat mapping
        for (int i = 0; i < 4; i++) seatOf[i] = parseSeat(seatOrder[i]);

        // Find dealer
        int dealerSeatIdx = parseSeat(dealerSeatStr);
        dealerIdx = -1;
        for (int i = 0; i < 4; i++) {
            if (seatOf[i] == dealerSeatIdx) { dealerIdx = i; break; }
        }
        if (dealerIdx < 0) dealerIdx = 3;
    }

    String after(String line) {
        int c = line.indexOf('：');
        if (c < 0) c = line.indexOf(':');
        if (c >= 0) return line.substring(c + 1);
        return line.replaceFirst("^[\\u4e00-\\u9fff]+", "");
    }

    int parseSeat(String s) {
        s = s.trim();
        switch (s) {
            case "东": case "東": return 0;
            case "南":            return 1;
            case "西":            return 2;
            case "北":            return 3;
            default:              return 0;
        }
    }

    // ===== Output =====

    StringBuilder out = new StringBuilder();
    void println(String s) { out.append(s).append("\n"); }

    void calculate() {
        for (int p = 0; p < N; p++) {
            printPlayerConditions(p);
        }
        printRyuukyoku();
        System.out.print(out.toString());
    }

    // ===== Per-player conditions =====

    void printPlayerConditions(int p) {
        println(names[p] + "晋级条件");
        boolean pIsOya = (p == dealerIdx);

        // --- Tsumo win ---
        if (pIsOya) {
            println("自摸\t" + calcOyaTsumoWin(p));
        } else {
            println("自摸\t" + calcKoTsumoWin(p));
        }

        println("=============================");

        // --- Ron wins (p wins from others) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            String cond = calcRonWin(p, other);
            if (!cond.isEmpty() && !cond.equals("不可能晋级")) {
                println(names[other] + "荣和\t" + cond);
            }
        }

        println("=============================");

        // --- Dealin (p deals into others) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            List<String> conds = calcDealin(p, other);
            for (String c : conds) {
                println("对" + names[other] + "放铳\t" + c);
            }
        }

        println("=============================");

        // --- Being tsumo'd (others tsumo, p pays) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            boolean otherIsOya = (other == dealerIdx);
            List<String> conds = calcBeingTsumod(p, other, otherIsOya);
            for (String c : conds) {
                if (otherIsOya) {
                    println("被" + names[other] + "亲家自摸\t" + c);
                } else {
                    println("被" + names[other] + "自摸\t" + c);
                }
            }
        }

        println("");
        println(names[p] + "危险区间:");
        printDangerZones(p);
        println("");
    }

    // ===== Tsumo win conditions =====

    String calcKoTsumoWin(int p) {
        // p is ko, tsumo win
        // honba: each player pays +100 extra
        for (int[] tv : KO_TSUMO) {
            int ko  = tv[0] + honba * 100;
            int oya = tv[1] + honba * 100;
            int[] sc = applyKoTsumo(p, ko, oya);
            if (qualifiesWithScores(sc, p, p)) {
                return labelKoTsumo(tv[0], tv[1]) + "以上";
            }
        }
        return "不可能晋级";
    }

    String calcOyaTsumoWin(int p) {
        // p is oya, tsumo win; all 3 others pay allPayment
        // honba: each player pays +100 extra
        for (int all : OYA_TSUMO) {
            int allH = all + honba * 100;
            int[] sc = applyOyaTsumo(p, allH);
            if (qualifiesWithScores(sc, p, p)) {
                return labelOyaTsumoAll(all) + "以上";
            }
        }
        return "不可能晋级";
    }

    // ===== Ron win condition (p wins from 'from') =====

    String calcRonWin(int p, int from) {
        boolean pIsOya = (p == dealerIdx);
        int[] thresholds = pIsOya ? OYA_RON : KO_RON;
        for (int v : thresholds) {
            int vH = v + honba * 300;
            int[] sc = applyRon(p, from, vH);
            if (qualifiesWithScores(sc, p, p)) {
                return labelRon(v, pIsOya) + "以上";
            }
        }
        return "不可能晋级";
    }

    // ===== Dealin condition (p pays to winner) =====

    List<String> calcDealin(int p, int winner) {
        boolean winnerIsOya = (winner == dealerIdx);
        int[] thresholds = winnerIsOya ? OYA_RON : KO_RON;

        boolean[] qual = new boolean[thresholds.length];
        for (int i = 0; i < thresholds.length; i++) {
            int vH = thresholds[i] + honba * 300;
            int[] sc = applyRon(winner, p, vH);
            qual[i] = qualifiesWithScores(sc, p, winner);
        }
        return buildRonRangeLabels(qual, thresholds, winnerIsOya);
    }

    List<String> buildRonRangeLabels(boolean[] qual, int[] thresholds, boolean isOya) {
        List<String> results = new ArrayList<>();
        int n = thresholds.length;
        int i = 0;
        while (i < n) {
            if (qual[i]) {
                int start = i;
                while (i < n && qual[i]) i++;
                int end = i - 1;
                String lo = labelRon(thresholds[start], isOya);
                String hi = labelRon(thresholds[end],   isOya);
                if (start == 0 && end == n - 1) {
                    results.add("3倍役满以下");
                } else if (start == 0) {
                    results.add(hi + "以下");
                } else if (end == n - 1) {
                    results.add(lo + "以上");
                } else {
                    // Qualifies only in a middle range: lo~hi
                    results.add(lo + "以上" + hi + "以下");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    // ===== Being tsumo'd conditions =====

    List<String> calcBeingTsumod(int p, int tsumoer, boolean tsumoerIsOya) {
        if (tsumoerIsOya) {
            boolean[] qual = new boolean[OYA_TSUMO.length];
            for (int i = 0; i < OYA_TSUMO.length; i++) {
                int allH = OYA_TSUMO[i] + honba * 100;
                int[] sc = applyOyaTsumo(tsumoer, allH);
                qual[i] = qualifiesWithScores(sc, p, tsumoer);
            }
            return buildOyaTsumoRangeLabels(qual);
        } else {
            boolean[] qual = new boolean[KO_TSUMO.length];
            for (int i = 0; i < KO_TSUMO.length; i++) {
                int ko  = KO_TSUMO[i][0] + honba * 100;
                int oya = KO_TSUMO[i][1] + honba * 100;
                int[] sc = applyKoTsumo(tsumoer, ko, oya);
                qual[i] = qualifiesWithScores(sc, p, tsumoer);
            }
            return buildKoTsumoRangeLabels(qual);
        }
    }

    List<String> buildOyaTsumoRangeLabels(boolean[] qual) {
        List<String> results = new ArrayList<>();
        int n = OYA_TSUMO.length;
        int i = 0;
        while (i < n) {
            if (qual[i]) {
                int start = i;
                while (i < n && qual[i]) i++;
                int end = i - 1;
                String lo = labelOyaTsumoAll(OYA_TSUMO[start]);
                String hi = labelOyaTsumoAll(OYA_TSUMO[end]);
                if (start == 0 && end == n - 1) {
                    results.add("3倍役满以下");
                } else if (start == 0) {
                    results.add(hi + "以下");
                } else if (end == n - 1) {
                    results.add(lo + "以上");
                } else {
                    results.add(lo + "以上" + hi + "以下");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    List<String> buildKoTsumoRangeLabels(boolean[] qual) {
        List<String> results = new ArrayList<>();
        int n = KO_TSUMO.length;
        int i = 0;
        while (i < n) {
            if (qual[i]) {
                int start = i;
                while (i < n && qual[i]) i++;
                int end = i - 1;
                String lo = labelKoTsumo(KO_TSUMO[start][0], KO_TSUMO[start][1]);
                String hi = labelKoTsumo(KO_TSUMO[end][0],   KO_TSUMO[end][1]);
                if (start == 0 && end == n - 1) {
                    results.add("3倍役满以下");
                } else if (start == 0) {
                    results.add(hi + "以下");
                } else if (end == n - 1) {
                    results.add(lo + "以上");
                } else {
                    results.add(lo + "以上" + hi + "以下");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    // ===== Danger zones =====

    void printDangerZones(int p) {
        for (int a = 0; a < N; a++) {
            if (a == p) continue;
            for (int b = 0; b < N; b++) {
                if (b == p || b == a) continue;
                // a deals into b (a pays b ron)
                boolean bIsOya = (b == dealerIdx);
                int[] thresholds = bIsOya ? OYA_RON : KO_RON;

                boolean[] danger = new boolean[thresholds.length];
                for (int i2 = 0; i2 < thresholds.length; i2++) {
                    int vH = thresholds[i2] + honba * 300;
                    int[] sc = applyRon(b, a, vH);
                    danger[i2] = !qualifiesWithScores(sc, p, b);
                }

                List<String> dzLabels = buildDangerRangeLabels(danger, thresholds, bIsOya);
                for (String dz : dzLabels) {
                    println(names[a] + "点" + names[b] + "\t" + dz);
                }
            }
        }
    }

    List<String> buildDangerRangeLabels(boolean[] danger, int[] thresholds, boolean isOya) {
        List<String> results = new ArrayList<>();
        int n = thresholds.length;
        int i = 0;
        while (i < n) {
            if (danger[i]) {
                int start = i;
                while (i < n && danger[i]) i++;
                int end = i - 1;
                String lo = labelRon(thresholds[start], isOya);
                String hi = labelRon(thresholds[end],   isOya);
                if (start == 0 && end == n - 1) {
                    results.add("任何点数都会丢晋级资格");
                } else if (start == 0) {
                    results.add(hi + "以下会丢晋级资格");
                } else if (end == n - 1) {
                    results.add(lo + "以上3倍役满以下会丢晋级资格");
                } else {
                    results.add(lo + "以上" + hi + "以下会丢晋级资格");
                }
            } else {
                i++;
            }
        }
        return results;
    }

    // ===== Ryuukyoku (exhaustive draw) =====

    void printRyuukyoku() {
        println("【听牌分支一览】");
        // Print in the exact order from the sample output
        int[] order = {0, 15, 1, 2, 4, 8, 14, 13, 11, 7, 3, 5, 9, 6, 10, 12};
        for (int mask : order) {
            printRyuukyokuCase(mask);
        }
    }

    void printRyuukyokuCase(int mask) {
        int tenpaiCount = Integer.bitCount(mask);
        int[] sc = Arrays.copyOf(scores, N);

        if (tenpaiCount > 0 && tenpaiCount < 4) {
            int gain = 3000 / tenpaiCount;
            int loss = 3000 / (4 - tenpaiCount);
            for (int i = 0; i < N; i++) {
                if ((mask >> i & 1) == 1) sc[i] += gain;
                else                      sc[i] -= loss;
            }
        }

        List<String> qualifiers = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            if (qualifiesRyuukyoku(sc, i)) qualifiers.add(names[i]);
        }

        boolean dealerTenpai = (mask >> dealerIdx & 1) == 1;
        String qualStr = "[" + String.join(", ", qualifiers) + "]晋级";
        String note    = dealerTenpai ? "，但" + names[dealerIdx] + "听牌而继续" : "";
        println(ryuukyokuCaseName(mask) + "：" + qualStr + note);
    }

    String ryuukyokuCaseName(int mask) {
        int count = Integer.bitCount(mask);
        if (count == 0) return "全员未听牌";
        if (count == 4) return "全员听牌";
        if (count == 1) {
            for (int i = 0; i < N; i++)
                if ((mask >> i & 1) == 1) return names[i] + "一人听牌";
        }
        if (count == 3) {
            for (int i = 0; i < N; i++)
                if ((mask >> i & 1) == 0) return names[i] + "一人未听牌";
        }
        // count == 2
        List<String> tn = new ArrayList<>();
        for (int i = 0; i < N; i++)
            if ((mask >> i & 1) == 1) tn.add(names[i]);
        return tn.get(0) + "、" + tn.get(1) + "听牌";
    }
