{"path": "/tmp/isolated_workspace_1091/MahjongPromotionCalculator.java", "content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * Riichi Mahjong Promotion Condition Calculator
 *
 * Supports: M-League, A-Rule (JPML), WRC, Saikouisen rules
 */
public class MahjongPromotionCalculator {

    // ===== Rule sets =====
    enum RuleSet {
        M_LEAGUE, A_RULE, WRC, SAIKOUISEN
    }

    // Uma tables: index 0=1st, 1=2nd, 2=3rd, 3=4th (in 0.1pt units to avoid floating point)
    static int[] getUma(RuleSet rule) {
        switch (rule) {
            case M_LEAGUE:   return new int[]{500, 100, -100, -300}; // *100 = actual pt
            case A_RULE:     return new int[]{200, 100, -100, -200};
            case WRC:        return new int[]{150, 50, -50, -150};
            case SAIKOUISEN: return new int[]{300, 100, -100, -300};
            default:         return new int[]{500, 100, -100, -300};
        }
    }

    static int getReturnScore(RuleSet rule) {
        switch (rule) {
            case M_LEAGUE: return 30000;
            default:       return 30000;
        }
    }

    // Standard ron payment thresholds (ko=child, as ron values)
    // Includes: 1000,2000,3900,5200,5800,7700,mangan=8000,haneman=12000,baiman=16000,sanbaiman=24000,yakuman=32000
    static final int[] KO_RON = {1000, 2000, 3900, 5200, 5800, 7700, 8000, 12000, 16000, 24000, 32000, 64000, 96000};
    static final int[] OYA_RON = {1500, 2900, 5800, 7700, 8700, 11600, 12000, 18000, 24000, 36000, 48000, 96000, 144000};
    // ko/oya tsumo breakpoints: {ko_payment, oya_payment} per player
    static final int[][] KO_TSUMO = {
        {300,500},{500,1000},{700,1300},{1000,2000},{2000,4000},{3000,6000},{4000,8000},{6000,12000},{8000,16000},{16000,32000},{24000,48000}
    };
    // Oya tsumo: all-pay amounts
    static final int[] OYA_TSUMO = {500,1000,2000,4000,8000,12000,16000,24000,32000,48000,96000,144000};

    // Label helpers
    static String koRonLabel(int v) {
        if (v >= 96000) return "3倍役满";
        if (v >= 64000) return "2倍役满";
        if (v >= 32000) return "役满";
        return String.valueOf(v);
    }
    static String oyaRonLabel(int v) {
        if (v >= 144000) return "3倍役满";
        if (v >= 96000) return "2倍役满";
        if (v >= 48000) return "亲役满";
        return String.valueOf(v);
    }
    static String koTsumoLabel(int ko, int oya) {
        return ko + "・" + oya;
    }
    static String oyaTsumoLabel(int all) {
        if (all >= 48000) return "役满all";
        return all + "all";
    }

    // ===== Game state =====
    static int N = 4; // number of players
    String[] names;
    int[] seats; // 0=East,1=South,2=West,3=North (index in order East/South/West/North)
    double[] priorPt;
    int[] scores;
    int promotionTop; // top-N qualify
    RuleSet rule;
    int kyoutaku; // riichi sticks on table (in 1000-pt units)
    int honba; // counter sticks
    int dealerIdx; // index of current dealer (0-3, index into names)
    // seats[i] = seat position of player i (0=East,1=South,2=West,3=North)

    // Is dealer parent (oya)?
    boolean isOya(int playerIdx) {
        return seats[playerIdx] == 3; // 北=3 is current dealer per input "当前亲家：北"
        // Actually we need to track which seat is dealer
    }

    // ===== PT calculation =====
    // Returns final pt for all players given final scores
    double[] calcFinalPt(int[] finalScores, int[] rankOrder) {
        // rankOrder[i] = rank of player i (1=1st, 2=2nd, etc.)
        int[] uma = getUma(rule);
        int ret = getReturnScore(rule);
        double[] pt = new double[N];
        for (int i = 0; i < N; i++) {
            int rank = rankOrder[i] - 1; // 0-indexed
            pt[i] = priorPt[i] + (finalScores[i] - ret) / 1000.0 + uma[rank] / 10.0;
        }
        return pt;
    }

    // Rank players by score (descending), ties broken by seat order (East > South > West > North, i.e., lower seat idx wins)
    int[] rankByScore(int[] sc) {
        Integer[] idx = new Integer[N];
        for (int i = 0; i < N; i++) idx[i] = i;
        Arrays.sort(idx, (a, b) -> {
            if (sc[b] != sc[a]) return sc[b] - sc[a];
            return seats[a] - seats[b]; // lower seat = higher priority in tie
        });
        int[] rank = new int[N];
        for (int i = 0; i < N; i++) rank[idx[i]] = i + 1;
        return rank;
    }

    // Compute final pt WITHOUT any game-end transfer (just as-is)
    // Returns pt array for all players
    double[] currentPt(int winner, int kyoutakuBonus) {
        // kyoutakuBonus goes to winner (in points)
        int[] sc = Arrays.copyOf(scores, N);
        if (winner >= 0) {
            sc[winner] += kyoutakuBonus;
        }
        int[] ranks = rankByScore(sc);
        return calcFinalPt(sc, ranks);
    }

    // Check if player p is in top-promotionTop given a pt array
    boolean qualifies(double[] pt, int p) {
        double myPt = pt[p];
        int better = 0;
        for (int i = 0; i < N; i++) {
            if (i != p && pt[i] > myPt) better++;
            // tie-break: if equal pt, seat order (lower seat = higher priority)
            // since uma is applied, ties after uma are broken by seat order in score ranking
        }
        return better < promotionTop;
    }

    // Check qualification for exactly the current state (no points exchanged, kyoutaku goes to rank1)
    // Used for ryuukyoku with winner = tenpai distribution
    boolean qualifiesWithScores(int[] sc, int p) {
        int[] ranks = rankByScore(sc);
        int[] uma = getUma(rule);
        int ret = getReturnScore(rule);
        double myPt = priorPt[p] + (sc[p] - ret) / 1000.0 + uma[ranks[p]-1] / 10.0;
        int better = 0;
        for (int i = 0; i < N; i++) {
            if (i == p) continue;
            double theirPt = priorPt[i] + (sc[i] - ret) / 1000.0 + uma[ranks[i]-1] / 10.0;
            if (theirPt > myPt) better++;
        }
        return better < promotionTop;
    }

    // ===== Main calculation =====

    public static void main(String[] args) throws Exception {
        MahjongPromotionCalculator calc = new MahjongPromotionCalculator();
        calc.readInput(new Scanner(System.in));
        calc.calculate();
    }

    void readInput(Scanner sc) {
        names = new String[4];
        seats = new int[4]; // seat[i] = seat of player i
        priorPt = new double[4];
        scores = new int[4];

        // Parse input
        String dealerSeat = "";
        String[] seatOrder = null;
        String line;

        while (sc.hasNextLine()) {
            line = sc.nextLine().trim();
            if (line.isEmpty()) continue;

            if (line.startsWith("当前亲家") || line.startsWith("当前親家")) {
                // e.g. "当前亲家：北"
                dealerSeat = line.replaceAll(".*[：:]", "").trim();
            } else if (line.startsWith("座次")) {
                // "座次： 东 南 西 北"
                String rest = line.replaceAll(".*[：:]", "").trim();
                seatOrder = rest.split("\\s+");
            } else if (line.startsWith("名字")) {
                String rest = line.replaceAll(".*[：:]", "").trim();
                String[] ns = rest.split("\\s+");
                for (int i = 0; i < 4; i++) names[i] = ns[i];
            } else if (line.startsWith("开始前总分") || line.startsWith("開始前総分")) {
                String rest = line.replaceAll("^开始前总分|^開始前総分", "").trim();
                String[] ps = rest.split("\\s+");
                for (int i = 0; i < 4; i++) priorPt[i] = Double.parseDouble(ps[i]);
            } else if (line.startsWith("当前分数") || line.startsWith("當前分數")) {
                String rest = line.replaceAll("^当前分数|^當前分數", "").trim();
                String[] ss = rest.split("\\s+");
                for (int i = 0; i < 4; i++) scores[i] = Integer.parseInt(ss[i]);
            } else if (line.startsWith("晋级条件") || line.startsWith("晉級條件")) {
                String rest = line.replaceAll(".*[：:]", "").trim();
                promotionTop = Integer.parseInt(rest.replaceAll("[^0-9]", ""));
            } else if (line.startsWith("规则") || line.startsWith("規則")) {
                String rest = line.replaceAll(".*[：:]", "").trim().toLowerCase();
                if (rest.contains("m-league") || rest.contains("mleague") || rest.contains("m_league")) {
                    rule = RuleSet.M_LEAGUE;
                } else if (rest.contains("wrc")) {
                    rule = RuleSet.WRC;
                } else if (rest.contains("a规") || rest.contains("a-rule") || rest.contains("arule") || rest.contains("a_rule")) {
                    rule = RuleSet.A_RULE;
                } else if (rest.contains("最高位") || rest.contains("saikouisen")) {
                    rule = RuleSet.SAIKOUISEN;
                } else {
                    rule = RuleSet.M_LEAGUE;
                }
            } else if (line.startsWith("供托") || line.startsWith("kyoutaku")) {
                String rest = line.replaceAll(".*[：:]", "").trim();
                kyoutaku = Integer.parseInt(rest.replaceAll("[^0-9]", ""));
            } else if (line.startsWith("本场") || line.startsWith("本場")) {
                String rest = line.replaceAll(".*[：:]", "").trim();
                honba = Integer.parseInt(rest.replaceAll("[^0-9]", ""));
            }
        }

        // Build seat mapping
        // seatOrder gives the seat names in order for names[]
        // e.g. seatOrder = ["东","南","西","北"] means player 0 is East, player 1 is South, etc.
        // Map Chinese seat name to index (0=East,1=South,2=West,3=North)
        if (seatOrder == null) seatOrder = new String[]{"东","南","西","北"};
        for (int i = 0; i < 4; i++) {
            seats[i] = seatIndex(seatOrder[i]);
        }

        // Find dealer index
        dealerIdx = -1;
        int dealerSeatIdx = seatIndex(dealerSeat);
        for (int i = 0; i < 4; i++) {
            if (seats[i] == dealerSeatIdx) {
                dealerIdx = i;
                break;
            }
        }
        if (dealerIdx < 0) dealerIdx = 3; // fallback
    }

    int seatIndex(String s) {
        switch (s.trim()) {
            case "东": case "東": case "east": return 0;
            case "南": case "south": return 1;
            case "西": case "west": return 2;
            case "北": case "north": return 3;
            default: return 0;
        }
    }

    String seatName(int idx) {
        switch (idx) {
            case 0: return "东";
            case 1: return "南";
            case 2: return "西";
            case 3: return "北";
            default: return "?";
        }
    }

    // ===== Core qualification check =====

    // Apply a point transfer and check if player p qualifies
    // transfers: array of {from, to, amount} where amount > 0 means transfer from[from] to [to]
    // Also add kyoutaku to winner if winner >= 0
    boolean qualifiesAfterTransfer(int p, int winner, int[][] transfers) {
        int[] sc = Arrays.copyOf(scores, N);
        for (int[] t : transfers) {
            sc[t[0]] -= t[2];
            sc[t[1]] += t[2];
        }
        if (winner >= 0) {
            sc[winner] += kyoutaku * 1000;
        }
        return qualifiesWithScores(sc, p);
    }

