    void calculateForPlayer(int p) {
        println(names[p] + "晋级条件");

        boolean pIsOya = (p == dealerIdx);

        // --- Tsumo section ---
        // Player p wins by tsumo
        // Find minimum tsumo payment for p to qualify
        if (pIsOya) {
            // Oya tsumo: all 3 others pay oyaTsumo amount each
            int minAll = -1;
            for (int[] tv : KO_TSUMO) {
                // skip - use OYA_TSUMO for oya
            }
            // Find threshold for oya
            String oyaTsumoCondition = calcOyaTsumoCondition(p);
            println("自摸\t" + oyaTsumoCondition);
        } else {
            // Ko tsumo: 2 ko pay ko_payment, 1 oya pays oya_payment
            String koTsumoCondition = calcKoTsumoCondition(p);
            println("自摸\t" + koTsumoCondition);
        }

        println("=============================");

        // --- Ron section (p wins, others deal in) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            boolean otherIsOya = (other == dealerIdx); // wait, p wins = p is the one who gets points
            // If p is oya (dealer), p gets oya ron payment
            // If p is ko (non-dealer), p gets ko ron payment
            String ronCondition = calcRonCondition(p, other);
            println(names[other] + "荣和\t" + ronCondition);
        }

        println("=============================");

        // --- Dealin section (p deals into others) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            // other wins by ron from p
            // If other is oya, p pays oya ron; if other is ko, p pays ko ron
            List<String> dealinConditions = calcDealinCondition(p, other);
            for (String cond : dealinConditions) {
                println("对" + names[other] + "放铳\t" + cond);
            }
        }

        println("=============================");

        // --- Being tsumo'd section (others tsumo, p pays) ---
        for (int other = 0; other < N; other++) {
            if (other == p) continue;
            boolean otherIsOya = (other == dealerIdx);
            List<String> tsumoedConditions = calcTsumoedCondition(p, other, otherIsOya);
            for (String cond : tsumoedConditions) {
